    "sequence" INTEGER NOT NULL DEFAULT 0,
    "version" INTEGER NOT NULL DEFAULT 1,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "Wireframe_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "Project" ("id") ON DELETE CASCADE ON UPDATE CASCADE
);
INSERT INTO Wireframe VALUES('cmrc09bag00091z187dj593eb','cmrby3y0000001znnofoo0a53','로그인','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap)}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a</style></head>\u000a<body data-screen="login">\u000a<div class="wf">\u000a <header class="wf-topbar">추노</header>\u000a <main class="wf-body" style="justify-content:center;text-align:center">\u000a   <div class="wf-ph" style="width:96px;height:96px;border-radius:24px;margin:0 auto"></div>\u000a   <div class="wf-title">장소 무관 경쟁 러닝</div>\u000a   <div class="wf-sub">방을 만들어 목표 거리를 먼저 완주하세요</div>\u000a   <div style="height:16px"></div>\u000a   <button class="wf-btn" data-p="카카오">카카오로 시작</button>\u000a   <button class="wf-btn" data-p="구글">구글로 시작</button>\u000a   <button class="wf-btn" data-p="Apple">Apple로 시작</button>\u000a   <div id="msg" class="wf-sub" style="min-height:18px"></div>\u000a </main>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''[data-p]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''[data-p]'').forEach(function(x){x.classList.remove(''wf-btn-primary'')});\u000a    b.classList.add(''wf-btn-primary'');\u000a    var m=document.getElementById(''msg''),p=b.getAttribute(''data-p'');\u000a    m.textContent=p+'' 인증 중…'';\u000a    setTimeout(function(){m.textContent=p+'' 로그인 완료 ✓'';},700);\u000a  });\u000a});\u000a</script>\u000a</body></html>'),1,1,1783510761832);
INSERT INTO Wireframe VALUES('cmrc0a433000d1z188fcz9jya','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-chip{border:1px solid var(--wf-line);border-radius:999px;padding:6px 12px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <form class="wf-body" id="f">\u000a   <div class="wf-field"><span class="wf-label">방 제목</span><input class="wf-input" placeholder="예: 아침 3km 대결"></div>\u000a   <div class="wf-field"><span class="wf-label">목표 거리</span>\u000a     <div style="display:flex;gap:8px;flex-wrap:wrap" id="dist">\u000a       <button type="button" class="wf-chip" data-v="2">2km</button>\u000a       <button type="button" class="wf-chip on" data-v="3">3km</button>\u000a       <button type="button" class="wf-chip" data-v="5">5km</button>\u000a       <button type="button" class="wf-chip" data-v="10">10km</button>\u000a     </div>\u000a   </div>\u000a   <div class="wf-field"><span class="wf-label">제한 시간 (분)</span><input class="wf-input" type="number" value="30"></div>\u000a   <div class="wf-field"><span class="wf-label">시작 시간</span><input class="wf-input" placeholder="2026-07-09 07:00:00"></div>\u000a   <div class="wf-field"><span class="wf-label">최대 인원</span>\u000a     <div style="display:flex;align-items:center;gap:14px">\u000a       <button type="button" class="wf-btn" id="minus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:24px;text-align:center">6</b>\u000a       <button type="button" class="wf-btn" id="plus">+</button>\u000a     </div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" type="submit">방 개설</button>\u000a   <div class="wf-card" id="summary" style="display:none"></div>\u000a </form>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''#dist .wf-chip'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#dist .wf-chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    c.classList.add(''on'');\u000a  });\u000a});\u000avar cap=6,capEl=document.getElementById(''cap'');\u000adocument.getElementById(''plus'').onclick=function(){if(cap<20){cap++;capEl.textContent=cap;}};\u000adocument.getElementById(''minus'').onclick=function(){if(cap>2){cap--;capEl.textContent=cap;}};\u000adocument.getElementById(''f'').addEventListener(''submit'',function(e){\u000a  e.preventDefault();\u000a  var d=document.querySelector(''#dist .on'').getAttribute(''data-v'');\u000a  var s=document.getElementById(''summary'');\u000a  s.style.display=''block'';\u000a  s.innerHTML=''<b>개설 확인</b><div class="wf-sub">목표 ''+d+''km · 최대 ''+cap+''명 · 상태 모집 중으로 생성됩니다</div>'';\u000a});\u000a</script>\u000a</body></html>'),3,1,1783510799151);
INSERT INTO Wireframe VALUES('cmrc0au5g000f1z18m7y9ak1r','cmrby3y0000001znnofoo0a53','대기실','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-label{font-size:13px;font-weight:600}\u000a</style></head>\u000a<body data-screen="waiting-room">\u000a<div class="wf">\u000a <header class="wf-topbar">← 대기실</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <div class="wf-title">아침 3km 대결</div><span class="wf-badge">모집 중</span>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">시작까지</div>\u000a     <div style="font-size:28px;font-weight:700" id="cd">09:58</div>\u000a     <div class="wf-sub">목표 3km · 제한 30분</div>\u000a   </div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-label">참가자</span><span class="wf-sub" id="count">3 / 6</span>\u000a   </div>\u000a   <div class="wf-list" id="plist">\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><b style="flex:1">나 (방장)</b><span class="wf-badge">HOST</span></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_김</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_이</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a   </div>\u000a   <button class="wf-btn" id="editToggle">조건 수정 (방장)</button>\u000a   <div class="wf-card" id="editBox" style="display:none">\u000a     <div class="wf-label" style="margin-bottom:8px">조건 수정 — 모집 중에만 가능</div>\u000a     <input class="wf-input" style="margin-bottom:8px" value="목표 3km">\u000a     <input class="wf-input" style="margin-bottom:8px" value="제한 30분">\u000a     <input class="wf-input" value="최대 6명">\u000a   </div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" disabled style="opacity:.6">시작 시간에 자동 시작</button>\u000a </main>\u000a</div>\u000a<script>\u000avar t=598,cd=document.getElementById(''cd'');\u000asetInterval(function(){ if(t>0){t--; var m=String(Math.floor(t/60)).padStart(2,''0''),s=String(t%60).padStart(2,''0''); cd.textContent=m+'':''+s;} },1000);\u000afunction refresh(){\u000a  var n=document.querySelectorAll(''#plist .wf-list-item'').length;\u000a  document.getElementById(''count'').textContent=n+'' / 6'';\u000a}\u000adocument.querySelectorAll(''.kick'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){ b.closest(''.wf-list-item'').remove(); refresh(); });\u000a});\u000adocument.getElementById(''editToggle'').addEventListener(''click'',function(){\u000a  var e=document.getElementById(''editBox'');\u000a  var open=e.style.display===''none'';\u000a  e.style.display=open?''block'':''none'';\u000a  this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000a</script>\u000a</body></html>'),4,1,1783510832933);
INSERT INTO Wireframe VALUES('cmrc0b903000h1z18bf2lnqec','cmrby3y0000001znnofoo0a53','러닝 (실시간 리더보드)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-rank{width:22px;text-align:center;font-weight:700}\u000a.wf-bar{height:8px;background:var(--wf-fill);border-radius:999px;overflow:hidden}\u000a.wf-bar>i{display:block;height:100%;background:var(--wf-ink);width:0}\u000a</style></head>\u000a<body data-screen="race">\u000a<div class="wf">\u000a <header class="wf-topbar">경기 중 · 아침 3km 대결</header>\u000a <main class="wf-body">\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">내 거리 (목표 3.0km)</div>\u000a     <div style="font-size:30px;font-weight:700"><span id="myd">0.00</span> km</div>\u000a     <div class="wf-bar" style="margin:8px 0"><i id="mybar"></i></div>\u000a     <div class="wf-sub">페이스 <span id="pace">--</span> /km · 남은시간 <span id="rt">30:00</span></div>\u000a   </div>\u000a   <div class="wf-ph" style="height:90px;display:flex;align-items:center;justify-content:center;color:var(--wf-muted)">지도 / 경로 (저해상도)</div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-title" style="font-size:15px">실시간 순위</span><span class="wf-sub" id="live">● LIVE</span>\u000a   </div>\u000a   <div class="wf-list" id="board"></div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn" id="quit">경주 포기</button>\u000a   <div id="msg" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a</div>\u000a<script>\u000avar goal=3.0;\u000avar runners=[{n:''나'',d:0,me:true},{n:''러너_김'',d:0.1},{n:''러너_이'',d:0.05},{n:''러너_박'',d:0.08}];\u000avar board=document.getElementById(''board'');\u000afunction render(){\u000a  var sorted=runners.slice().sort(function(a,b){return b.d-a.d});\u000a  board.innerHTML='''';\u000a  sorted.forEach(function(r,i){\u000a    var row=document.createElement(''div''); row.className=''wf-list-item'';\u000a    row.innerHTML=''<span class="wf-rank">''+(i+1)+''</span><span style="flex:1">''+r.n+(r.me?'' <span class=\\"wf-badge\\">나</span>'':'''')+''</span><b>''+r.d.toFixed(2)+'' km</b>'';\u000a    if(r.me) row.style.background=''var(--wf-fill)'';\u000a    board.appendChild(row);\u000a  });\u000a  var me=runners[0];\u000a  document.getElementById(''myd'').textContent=me.d.toFixed(2);\u000a  document.getElementById(''mybar'').style.width=Math.min(100,me.d/goal*100)+''%'';\u000a  document.getElementById(''pace'').textContent=me.d>0?(6+ (0.5-0)).toFixed(1).replace(''.'',"''")+''"'':"--";\u000a}\u000avar tick=setInterval(function(){\u000a  runners.forEach(function(r){ if(r.d<goal) r.d+=Math.random()*0.04+0.01; });\u000a  render();\u000a  var done=runners[0].d>=goal;\u000a  if(runners.some(function(r){return r.d>=goal})){\u000a    var first=runners.slice().sort(function(a,b){return b.d-a.d})[0];\u000a    if(first.d>=goal){ document.getElementById(''live'').textContent=''● 완주자 발생''; }\u000a  }\u000a  if(runners.every(function(r){return r.d>=goal})){ clearInterval(tick); document.getElementById(''live'').textContent=''경기 종료''; }\u000a},900);\u000arender();\u000adocument.getElementById(''quit'').addEventListener(''click'',function(){\u000a  clearInterval(tick); document.getElementById(''msg'').textContent=''포기 처리 — 완주자 뒤 거리순으로 기록됩니다'';\u000a  this.classList.add(''wf-btn-primary'');\u000a});\u000a</script>\u000a</body></html>'),5,1,1783510852180);
INSERT INTO Wireframe VALUES('cmrc0bs3h000j1z18k97p9a0k','cmrby3y0000001znnofoo0a53','결과','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-rank{width:22px;text-align:center;font-weight:700}\u000a.podium{display:flex;align-items:flex-end;gap:8px;justify-content:center}\u000a.podium .col{flex:1;text-align:center}\u000a.podium .bar{background:var(--wf-fill);border-radius:8px 8px 0 0;display:flex;align-items:flex-start;justify-content:center;padding-top:6px;font-weight:700}\u000a</style></head>\u000a<body data-screen="result">\u000a<div class="wf">\u000a <header class="wf-topbar">경기 결과</header>\u000a <main class="wf-body">\u000a   <div class="wf-title" style="text-align:center">아침 3km 대결</div>\u000a   <div class="wf-sub" style="text-align:center">목표 3km · 참가 4명 · 종료</div>\u000a   <div class="podium">\u000a     <div class="col"><div class="wf-sub">러너_김</div><div class="bar" style="height:56px">2</div></div>\u000a     <div class="col"><div class="wf-sub">나</div><div class="bar" style="height:84px">1</div></div>\u000a     <div class="col"><div class="wf-sub">러너_박</div><div class="bar" style="height:40px">3</div></div>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">내 기록</div>\u000a     <div style="font-size:22px;font-weight:700">1등 · 3.00km</div>\u000a     <div class="wf-sub">기록 15''42" · 평균 페이스 5''14"/km</div>\u000a   </div>\u000a   <span class="wf-title" style="font-size:15px">전체 순위</span>\u000a   <div class="wf-list" id="rank">\u000a     <div class="wf-list-item" style="background:var(--wf-fill)"><span class="wf-rank">1</span><span style="flex:1">나 <span class="wf-badge">나</span></span><b>15''42"</b></div>\u000a     <div class="wf-list-item"><span class="wf-rank">2</span><span style="flex:1">러너_김</span><b>16''03"</b></div>\u000a     <div class="wf-list-item"><span class="wf-rank">3</span><span style="flex:1">러너_박</span><b>17''20"</b></div>\u000a     <div class="wf-list-item"><span class="wf-rank">4</span><span style="flex:1">러너_이 <span class="wf-badge">미완주</span></span><b>2.4km</b></div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" id="share">결과 공유</button>\u000a   <div id="msg" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''#rank .wf-list-item'').forEach(function(r){\u000a  r.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#rank .wf-list-item'').forEach(function(x){x.style.outline=''none''});\u000a    r.style.outline=''2px solid var(--wf-ink)'';\u000a  });\u000a});\u000adocument.getElementById(''share'').addEventListener(''click'',function(){\u000a  document.getElementById(''msg'').textContent=''결과 링크가 복사되었습니다 ✓'';\u000a});\u000a</script>\u000a</body></html>'),6,1,1783510876925);
