CREATE INDEX "Issue_projectId_idx" ON "Issue"("projectId");
CREATE INDEX "Issue_parentId_idx" ON "Issue"("parentId");
CREATE INDEX "Issue_planId_idx" ON "Issue"("planId");
CREATE INDEX "Issue_domainId_idx" ON "Issue"("domainId");
